// // This module implements a multi-level selector where Y is selected based on the states of A1 and A2. If A1 is high, Y is assigned B1. If A1 is low and A2 is high, Y is assigned C1. Otherwise, Y defaults to D1.
module top_module(
    input  A1,
    input  A2,
    input  B1,
    input  C1,
    input  D1,
    output Y
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign Y = (A1) ? B1 : ((A2) ? C1 : D1);

endmodule
